namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9\-]+$", ErrorMessage = "Invalid Student ID format.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published extensively in top-tier conferences.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for a decade before joining academia. She specializes in distributed database systems.", IsFeatured = false },
            new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with a passion for making calculus accessible to all students.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and eigenvectors.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra and numerical methods.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 3, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Fri Lab", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist who brings real-world research into the classroom.", IsFeatured = true },
            new() { Id = 7, DepartmentId = 3, CourseCode = "PHYS 220", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Priya Patel", InstructorBio = "Dr. Patel is a theoretical physicist specializing in quantum electrodynamics.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 4, CourseCode = "ENG 110", Title = "Academic Writing", Description = "Develop clear, persuasive academic writing skills. Emphasis on argumentation, research methods, and citation.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", InstructorName = "Prof. Linda Torres", InstructorBio = "Prof. Torres has published three books on rhetoric and composition pedagogy.", IsFeatured = false },
            new() { Id = 9, DepartmentId = 4, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown specializes in 20th-century American fiction and has received multiple teaching awards.", IsFeatured = true },
            new() { Id = 10, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Angela Davis", InstructorBio = "Dr. Davis is an ancient history scholar with archaeological field experience across three continents.", IsFeatured = false },
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public string GetDepartmentName(int departmentId) =>
        _departments.FirstOrDefault(d => d.Id == departmentId)?.Name ?? "Unknown";
}

