@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetAllDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var courses = CatalogService.SearchCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@CatalogService.GetDepartmentName(course.DepartmentId)</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Your enrollment request has been received. You will be notified once it has been processed.</p>
        <a href="courses" class="btn btn-primary">Back to Course Catalog</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
                <DataAnnotationsValidator />
                <AntiforgeryToken />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" placeholder="e.g. STU-12345" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in CatalogService.GetAllCourses())
                        {
                            <option value="@course.Id">@course.CourseCode - @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

